from typing import Any

class Column:
    def __init__(self, coerce=str):
        self._coerce = coerce
        # BUG: Descriptor should populate .name in __set_name__, but we skip it
        # and rely on a for-loop below that never actually calls __set_name__.

    def __get__(self, instance, owner):
        if instance is None:
            return self
        return instance.__dict__.get(self.name)

    def __set__(self, instance, value):
        instance.__dict__[self.name] = self._coerce(value)


class ModelMeta(type):
    def __new__(mcs, name, bases, ns):
        cls = super().__new__(mcs, name, bases, ns)
        # BUG: Iterating ns.items() but Column instances were added AFTER class
        # creation via ``cls.attr = Column()`` in the user model, so __set_name__
        # was never triggered for those.
        return cls


class Model(metaclass=ModelMeta):
    def __init__(self, **kwargs):
        for k, v in kwargs.items():
            try:
                setattr(self, k, v)
            except AttributeError as e:
                raise AttributeError(f"column {k!r} failed to bind: {e}") from e


class UserRow(Model):
    pass


# User patches class dynamically (real pattern in plugin systems)
UserRow.name = Column(str)
UserRow.age  = Column(int)

if __name__ == "__main__":
    row = UserRow(name="alice")
    print(row.name)
